function buttonStyle(kind) {
  const variants = {
    primary: {
      width: "100%",
      background: "linear-gradient(135deg, #6b0000 0%, #aa1111 50%, #c0392b 100%)",
      border: "none",
      color: "#fff",
      boxShadow: "0 6px 24px rgba(170,17,17,.32)",
    },
    ghost: {
      background: "rgba(255,255,255,.045)",
      border: "1px solid rgba(255,255,255,.10)",
      color: "rgba(255,255,255,.72)",
    },
    danger: {
      background: "rgba(170,17,17,.12)",
      border: "1px solid rgba(170,17,17,.32)",
      color: "#fca5a5",
    },
    success: {
      background: "rgba(34,197,94,.12)",
      border: "1px solid rgba(34,197,94,.28)",
      color: "#86efac",
    },
    warning: {
      background: "rgba(245,158,11,.12)",
      border: "1px solid rgba(245,158,11,.30)",
      color: "#fbbf24",
    },
  };

  return {
    ...variants[kind],
    minHeight: 38,
    borderRadius: 9,
    padding: "9px 12px",
    display: "inline-flex",
    alignItems: "center",
    justifyContent: "center",
    gap: 7,
    cursor: "pointer",
    fontSize: 11,
    fontWeight: 700,
    letterSpacing: 1.2,
    textTransform: "uppercase",
    fontFamily: "'Source Sans 3', sans-serif",
  };
}

function messageStyle(kind) {
  const isError = kind === "error";
  return {
    display: "flex",
    alignItems: "center",
    gap: 10,
    padding: "12px 15px",
    background: isError ? "rgba(170,17,17,.10)" : "rgba(21,128,61,.10)",
    border: isError ? "1px solid rgba(170,17,17,.30)" : "1px solid rgba(34,197,94,.25)",
    borderLeft: isError ? "3px solid #aa1111" : "3px solid #22c55e",
    borderRadius: 9,
    color: isError ? "#fca5a5" : "#86efac",
    marginBottom: 24,
    fontSize: 13,
  };
}
